```class Solution {
public:
    vector<int> gardenNoAdj(int n, vector<vector<int>>& paths) {
        vector<vector<int>> graph(n + 1);
        for (auto& path : paths) {
            graph[path[0]].push_back(path[1]);
            graph[path[1]].push_back(path[0]);
        }
        vector<int> ans(n + 1);
        for (int i = 1; i <= n; i++) {
            set<int> used;
            for (int j : graph[i]) {
                used.insert(ans[j]);
            }
            for (int k = 1; k <= 4; k++) {
                if (used.count(k) == 0) {
                    ans[i] = k;
                    break;
                }
            }
        }
        ans.erase(ans.begin());
        return ans;
    }
};```
